package ru.memearena.scout.api; import org.springframework.web.bind.annotation.*; import ru.memearena.scout.domain.*; import ru.memearena.scout.infrastructure.*; import ru.memearena.user.infrastructure.UserProfileRepository; import java.time.*; import java.util.*; import static ru.memearena.scout.api.ScoutDtos.*;
@RestController @RequestMapping("/api/v1/users/leaderboard") public class ScoutLeaderboardController{ private final UserScoutStatsRepository stats; private final UserProfileRepository users; private final ScoutPointEventRepository events; private final Clock clock; public ScoutLeaderboardController(UserScoutStatsRepository s,UserProfileRepository u,ScoutPointEventRepository e,Clock c){stats=s;users=u;events=e;clock=c;} @GetMapping public LeaderboardResponse board(@RequestParam(defaultValue="ALL_TIME") String period,@RequestParam(defaultValue="50") int limit){var us=users.findAll(); Map<UUID,ru.memearena.scout.domain.UserScoutStats> sm=new HashMap<>(); stats.findAll().forEach(s->sm.put(s.getUserId(),s)); Instant since=Instant.now(clock).minus(Duration.ofDays(7)); var rows=us.stream().map(u->{var st=sm.getOrDefault(u.getId(),new UserScoutStats(u.getId(),Instant.now(clock))); long pts=period.equals("WEEK")?events.weeklyPoints(u.getId(),since):st.getScoutPoints(); return new Object[]{u,st,pts};}).sorted((a,b)->{long pa=(Long)a[2],pb=(Long)b[2]; int c=Long.compare(pb,pa); if(c!=0)return c; var sa=(UserScoutStats)a[1]; var sb=(UserScoutStats)b[1]; c=Long.compare(sb.getSuccessfulPredictions(),sa.getSuccessfulPredictions()); if(c!=0)return c; c=Comparator.nullsLast(Double::compareTo).reversed().compare(sa.accuracy(),sb.accuracy()); if(c!=0)return c; return ((ru.memearena.user.domain.UserProfile)a[0]).getCreatedAt().compareTo(((ru.memearena.user.domain.UserProfile)b[0]).getCreatedAt());}).limit(Math.min(100,limit)).toList(); List<LeaderboardItem> items=new ArrayList<>(); int pos=1; for(Object[] r:rows){var u=(ru.memearena.user.domain.UserProfile)r[0]; var st=(UserScoutStats)r[1]; long pts=(Long)r[2]; items.add(new LeaderboardItem(pos++,u.getId(),u.getNickname(),pts,ScoutRank.fromPoints(st.getScoutPoints()),st.accuracy(),st.getSuccessfulPredictions(),st.getBestSuccessStreak()));} return new LeaderboardResponse(period,items);} }
